import os

tests_dir = "/home/barista/agentic_barista/runs/synthesize/datagramsocket/run_1/datagramsocket/tests"

# Imports to add after the package declaration
imports = """import java.net.DatagramSocket;
import java.net.DatagramPacket;
import java.net.InetAddress;
import java.net.SocketAddress;
import java.net.DatagramSocketImpl;
import java.net.NetworkInterface;
"""

files_processed = 0
for root, dirs, files in os.walk(tests_dir):
    for fname in sorted(files):
        if fname.endswith('.java'):
            fpath = os.path.join(root, fname)
            with open(fpath, 'r') as f:
                content = f.read()
            # Add imports after the package line
            lines = content.split('\n')
            new_lines = []
            imports_added = False
            for line in lines:
                new_lines.append(line)
                if line.startswith('package ') and not imports_added:
                    new_lines.append(imports.rstrip())
                    imports_added = True
            new_content = '\n'.join(new_lines)
            with open(fpath, 'w') as f:
                f.write(new_content)
            files_processed += 1

print(f"Added imports to {files_processed} files")
EOF

